import{_ as a,o as r,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"10. In Charge Allowances","description":"","frontmatter":{"title":"10. In Charge Allowances","eba":"Health Allied & Managers Admin 2021-2025","topics":["allowances"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/allowances/10-in-charge-allowances.md","filePath":"ebas/has-managers-admin/health-allied-services/allowances/10-in-charge-allowances.md"}'),t={name:"ebas/has-managers-admin/health-allied-services/allowances/10-in-charge-allowances.md"};function s(l,e,p,c,g,i){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_10-in-charge-allowances" tabindex="-1">10. In Charge Allowances <a class="header-anchor" href="#_10-in-charge-allowances" aria-label="Permalink to &quot;10. In Charge Allowances&quot;">​</a></h1><p><strong>10.1</strong> An Employee will be paid an In-charge Allowance where they are appointed or delegated to exercise control over other Employees, as follows: % Extent of control: Allowance</p><p>In charge of 1 to 9 other 7% Employees</p><p>In charge of 10 to 29 other 10% Employees</p><p>In charge of 30 or more Employees 15%</p><p><strong>10.2</strong> Provided that subclause 10.1 does not apply to the following classifications of Employee:</p><p><strong>(a)</strong> Chef Grade A</p><p><strong>(b)</strong> Chef Grade B</p><p><strong>(c)</strong> Chef Grade C</p><p><strong>(d)</strong> Chef Grade D</p><p><strong>(e)</strong> Second Grade Cook Grade A</p><p><strong>(f)</strong> Second Grade Cook Grade B</p><p><strong>(g)</strong> Second Grade Cook Grade C</p><p><strong>(h)</strong> Second Grade Cook Grade D</p><p><strong>(i)</strong> Gardener Advanced</p><p><strong>(j)</strong> Handyperson Advanced</p><p><strong>(k)</strong> Printer Advanced</p><p><strong>(l)</strong> Pathology Collector Reliever/Mobile Collector</p><p><strong>(m)</strong> Technical, Therapy &amp; Personal Care Supervisor</p><p><strong>(n)</strong> Pathology Collector Grade 4</p><p><strong>(o)</strong> Patient Transport Officer Grade 3</p><p><strong>(p)</strong> Gardener Superintendent</p><p><strong>(q)</strong> General Service Supervisor</p><p><strong>(r)</strong> Food Services Supervisor</p><p><strong>(s)</strong> Security Officer Grade 3</p><p><strong>(t)</strong> Health Care Worker Coordinator/Supervisor Technical or Therapy Supervisor</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>(u)</strong> Grade 3 – Dental Assistant Coach</p><p><strong>(v)</strong> Grade 4 - Senior Dental Assistant</p><p><strong>(w)</strong> Grade 5 – Theatre Technician</p><p><strong>(x)</strong> Liver Transplant Technologists</p><p><strong>(y)</strong> Grade 5 – Instrument Technician</p><p><strong>(z)</strong> Dual Qualified Technicians</p><p><strong>(aa)</strong> Pharmacy Technician Grade 3</p><p><strong>(bb)</strong> Pharmacy Technician Grade 4</p><p><strong>(cc)</strong> Anaesthetic Technician Grade 3</p><p><strong>(dd)</strong> Anaesthetic Technician Grade 4</p><p><strong>(ee)</strong> Dental Maintenance Technician</p><p><strong>10.3</strong> The percentage In-charge Allowance is calculated on the base rate payable to the Employee pursuant to <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>.</p><p><strong>10.4</strong> The In-Charge Allowance will be additional to any other allowance to which the Employee is entitled under the Agreement.</p><p>Plain language terms: in-charge, leading hand.</p>',41)])])}const m=a(t,[["render",s]]);export{d as __pageData,m as default};
